function emitObjectMasks(objectMasks, trackedObjects) {
  const universe = (trackedObjects && trackedObjects.length) ? trackedObjects : ['person','car','dog','cat','bird','package'];
  const byType = {};
  for (const m of objectMasks) {
    const targets = m.objectType === 'all' ? universe : [m.objectType];
    for (const t of targets) (byType[t] ??= []).push({ mask: m, fromAll: m.objectType === 'all' });
  }
  let out = 'objects:\n  filters:\n';
  for (const [type, entries] of Object.entries(byType)) {
    out += `    ${type}:\n      mask:\n`;
    for (const e of entries) out += `        - ${coordString(e.mask.points)}${e.fromAll ? '  # from "all objects" mask' : ''}\n`;
  }
  return out;
}
